import{_ as n,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"31. Superannuation","description":"","frontmatter":{"title":"31. Superannuation","eba":"Health Allied & Managers Admin 2021-2025","topics":["wages","superannuation","preliminary","definitions"]},"headers":[],"relativePath":"ebas/has-managers-admin/common-terms/wages/31-superannuation.md","filePath":"ebas/has-managers-admin/common-terms/wages/31-superannuation.md"}'),r={name:"ebas/has-managers-admin/common-terms/wages/31-superannuation.md"};function i(s,e,p,u,l,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_31-superannuation" tabindex="-1">31. Superannuation <a class="header-anchor" href="#_31-superannuation" aria-label="Permalink to &quot;31. Superannuation&quot;">​</a></h1><p>The subject of superannuation is dealt with extensively by federal legislation which prescribes the obligations and entitlements regarding superannuation. This clause is ancillary to and supplements those provisions.</p><p><strong>31.1</strong> Definitions In this clause:</p><p><strong>(a)</strong> default fund means the Aware Super superannuation fund (or its successor) while it provides a &quot;MySuper product&quot; as defined by the Act.</p><p><strong>(b)</strong> preferred superannuation fund means a fund that meets the definition of a superannuation fund in the Superannuation Guarantee (Administration) Act 1992 (Cth).</p><p><strong>31.2</strong> Existing Employees</p><p>Employees will have the choice to nominate that the Employer contributions and their own contributions are made to the Employee&#39;s preferred superannuation fund (as defined above).</p><p><strong>31.3</strong> New Employees The Employer will offer to make superannuation contributions on behalf of an Employee to:</p><p><strong>(a)</strong> the Employee&#39;s preferred superannuation fund;</p><p><strong>(b)</strong> Aware Super superannuation funds (or successor); or,</p><p><strong>(c)</strong> HESTA (or successor).</p><p><strong>31.4</strong> Where new Employee does not nominate fund If the Employee does not nominate a fund, the Employer will pay the Employee&#39;s superannuation contributions to the default fund.</p><p><strong>31.5</strong> Calculation of superannuation contributions Superannuation contributions paid by the Employer will be calculated and paid on:</p><p><strong>(a)</strong> ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre salary packaging earnings, and</p><p><strong>(b)</strong> any additional amounts consistent with the trust deed of the superannuation fund; and</p><p><strong>(c)</strong> any payment for a period of paid parental leave under <a href="/eba/ebas/has-managers-admin/common-terms/leave/59-parental-leave.html">clause 59</a> until 30 June 2021, after which superannuation shall be paid on parental leave (paid and unpaid) in accordance with subclause 31.7.</p><p><strong>31.6</strong> Frequency of contributions From 1 July 2021, the Employer will make superannuation contributions to the superannuation fund nominated by employees covered by this agreement on a monthly basis (each four weeks).</p><p><strong>31.7</strong> Superannuation during parental leave – from 1 July 2021 From 1 July 2021, the Employer will make superannuation contributions throughout any period of parental leave, paid or unpaid. Such contributions will be calculated as follows:</p><p><strong>(a)</strong> The Employee&#39;s ordinary time earnings as defined in the Superannuation Guarantee (Administration) Act 1992 (Cth) calculated on the Employee&#39;s pre salary packaging earnings and any additional amounts consistent with the trust deed of the superannuation fund over 26 full pay periods immediately prior to commencing parental leave and divided by 52 (Weekly Parental Leave Super Contribution);</p><p><strong>(b)</strong> The Weekly Parental Leave Super Contribution will be paid during each week of Parental Leave (both paid and unpaid) save that:</p><p><strong>(i)</strong> the Employee will receive a pro rata payment for a period less than one week; and</p><p><strong>(ii)</strong> where, during the period of parental leave (either paid or unpaid), the Employee&#39;s rate of pay increases under clause 28, the Employee&#39;s pre salary packaging earnings as calculated above will be increased accordingly from the relevant date and superannuation paid on the increased amount.</p><p><strong>31.8</strong> Voluntary contributions</p><p><strong>(a)</strong> An Employee may request in writing that an Employer pay on their behalf a specified amount from their post-taxation pay into the Employee’s superannuation fund.</p><p><strong>(b)</strong> An Employee may adjust the amount the Employer authorises the Employer to pay from their wages from the first of the month following the giving of three months’ written notice to the Employer.</p><p><strong>(c)</strong> The Employer must pay the amount authorised under clauses 31.8(a) or 31.8(b) no later than 28 days after the end of the month in which the authorised deduction was made.</p><p>Plain language terms: super, employer contribution, SG, retirement fund.</p>',27)])])}const c=n(r,[["render",i]]);export{m as __pageData,c as default};
